// 三载体一致:产 PDF 字节,零 DOM 足迹;非 text 类型需传 plugins
import { generate } from 'https://cdn.jsdelivr.net/npm/@pdfme/generator@6.1.12/+esm';
import { text, image, table, line, rectangle, barcodes } from 'https://cdn.jsdelivr.net/npm/@pdfme/schemas@6.1.12/+esm';
const plugins = { text, image, table, line, rectangle, qrcode: barcodes.qrcode };
const pdf = await generate({ template: data.template, inputs: data.inputs, plugins });
const blob = new Blob([pdf], { type: 'application/pdf' });
